args.sparql:
SELECT ?artist ?artistLabel (COUNT(DISTINCT ?single) AS ?count) WHERE { 
  {
    ?single wdt:P31 wd:Q134556 .
    ?single wdt:P175 ?artist .
    ?single p:P4527 ?chartPosition .
    ?chartPosition pq:P1617 ?rank .
    FILTER(STR(?rank) = "1") .
  }
  UNION 
  {
    ?single wdt:P31 wd:Q134556 .
    ?single wdt:P175 ?artist .
    ?single p:P4527 ?chartPosition .
    ?chartPosition pq:P1617 ?rank .
    FILTER(?rank = 1) .
  }
  OPTIONAL { ?artist rdfs:label ?artistLabel FILTER(LANG(?artistLabel) = "en") }
}
GROUP BY ?artist ?artistLabel
ORDER BY DESC(?count)
LIMIT 1
